export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  tryConsume(): boolean {
    this.refill();
    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;
    const newTokens = (elapsed * this.refillRate) / 1000;
    this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);
    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];
export type Filter = (record: Record) => boolean;

export function andFilter(...filters: Filter[]): Filter {
  return (r: Record) => filters.every((f) => f(r));
}

export function orFilter(...filters: Filter[]): Filter {
  return (r: Record) => filters.some((f) => f(r));
}

export function notFilter(filter: Filter): Filter {
  return (r: Record) => !filter(r);
}

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      const combined = andFilter(...this.filters);
      result = result.filter(combined);
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  if (!field || field.length === 0) {
    throw new CronParseError(`Empty field: ${fieldName}`, fieldName);
  }

  const parts = field.split(',');
  const values = new Set<number>();

  for (const part of parts) {
    parseFieldPart(part, min, max, fieldName).forEach(v => values.add(v));
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseFieldPart(part: string, min: number, max: number, fieldName: string): number[] {
  let step = 1;
  let rangePart = part;

  if (part.includes('/')) {
    const stepSplit = part.split('/');
    if (stepSplit.length !== 2) {
      throw new CronParseError(`Invalid step in field ${fieldName}: ${part}`, fieldName);
    }
    rangePart = stepSplit[0];
    const stepStr = stepSplit[1];
    if (!/^\d+$/.test(stepStr)) {
      throw new CronParseError(`Invalid step value in field ${fieldName}: ${stepStr}`, fieldName);
    }
    step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new CronParseError(`Step must be positive in field ${fieldName}`, fieldName);
    }
  }

  let rangeStart: number;
  let rangeEnd: number;

  if (rangePart === '*') {
    rangeStart = min;
    rangeEnd = max;
  } else if (rangePart.includes('-')) {
    const rangeSplit = rangePart.split('-');
    if (rangeSplit.length !== 2) {
      throw new CronParseError(`Invalid range in field ${fieldName}: ${rangePart}`, fieldName);
    }
    if (!/^\d+$/.test(rangeSplit[0]) || !/^\d+$/.test(rangeSplit[1])) {
      throw new CronParseError(`Invalid range numbers in field ${fieldName}: ${rangePart}`, fieldName);
    }
    rangeStart = parseInt(rangeSplit[0], 10);
    rangeEnd = parseInt(rangeSplit[1], 10);
    if (rangeStart > rangeEnd) {
      throw new CronParseError(`Range start greater than end in field ${fieldName}: ${rangePart}`, fieldName);
    }
  } else {
    if (!/^\d+$/.test(rangePart)) {
      throw new CronParseError(`Invalid value in field ${fieldName}: ${rangePart}`, fieldName);
    }
    const val = parseInt(rangePart, 10);
    if (part.includes('/')) {
      rangeStart = val;
      rangeEnd = max;
    } else {
      rangeStart = val;
      rangeEnd = val;
    }
  }

  if (rangeStart < min || rangeStart > max || rangeEnd < min || rangeEnd > max) {
    throw new CronParseError(`Value out of range [${min}-${max}] in field ${fieldName}: ${part}`, fieldName);
  }

  const result: number[] = [];
  for (let i = rangeStart; i <= rangeEnd; i += step) {
    result.push(i);
  }
  return result;
}

export function parseCron(expression: string): CronSchedule {
  if (typeof expression !== 'string') {
    throw new CronParseError('Expression must be a string');
  }
  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new CronParseError('Empty expression');
  }
  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new CronParseError(`Expected 5 fields, got ${fields.length}`);
  }

  const [minField, hourField, domField, monthField, dowField] = fields;

  return {
    minutes: parseField(minField, 0, 59, 'minute'),
    hours: parseField(hourField, 0, 23, 'hour'),
    daysOfMonth: parseField(domField, 1, 31, 'day-of-month'),
    months: parseField(monthField, 1, 12, 'month'),
    daysOfWeek: parseField(dowField, 0, 6, 'day-of-week'),
    original: expression,
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function ok(data: unknown, status = 200): Response {
  return { status, body: { success: true, data } };
}

function err(status: number, error: string): Response {
  return { status, body: { success: false, error } };
}

function checkAuth(req: Request): Response | null {
  const token = req.headers["authorization"];
  if (!token) return err(401, "Authorization required");
  if (token !== "Bearer valid-token") return err(401, "Invalid token");
  return null;
}

function requireId(req: Request): string | Response {
  const id = req.params["id"];
  if (!id) return err(400, "Validation failed: id parameter is required");
  return id;
}

function requireBody(req: Request): Record<string, unknown> | Response {
  if (!req.body) return err(400, "Request body is required");
  return req.body as Record<string, unknown>;
}

function isResponse(v: unknown): v is Response {
  return typeof v === "object" && v !== null && "status" in (v as object) && "body" in (v as object);
}

function handleGet(req: Request): Response {
  const id = req.params["id"];
  if (!id) return ok(Array.from(store.values()));
  const item = store.get(id);
  return item ? ok(item) : err(404, "Item not found");
}

function handlePost(req: Request): Response {
  const body = requireBody(req);
  if (isResponse(body)) return body;
  if (!body["name"] || typeof body["name"] !== "string") {
    return err(400, "Validation failed: name is required");
  }
  const providedId = body["id"] as string | undefined;
  if (providedId && store.has(providedId)) {
    return err(409, "Item already exists");
  }
  const now = Date.now();
  const newId = providedId || `item-${now}`;
  const item: Item = {
    id: newId,
    name: body["name"] as string,
    status: "active",
    createdAt: now,
    updatedAt: now,
  };
  store.set(newId, item);
  return ok(item, 201);
}

function applyUpdates(item: Item, data: Record<string, unknown>): Item {
  const updated: Item = { ...item, updatedAt: Date.now() };
  if (data["name"] && typeof data["name"] === "string") {
    updated.name = data["name"] as string;
  }
  if (data["status"] === "active" || data["status"] === "archived") {
    updated.status = data["status"];
  }
  return updated;
}

function handlePut(req: Request): Response {
  const body = requireBody(req);
  if (isResponse(body)) return body;
  const idResult = requireId(req);
  if (isResponse(idResult)) return idResult;
  const existing = store.get(idResult);
  if (!existing) return err(404, "Item not found");
  const updated = applyUpdates(existing, body);
  store.set(idResult, updated);
  return ok(updated);
}

function handleDelete(req: Request): Response {
  const idResult = requireId(req);
  if (isResponse(idResult)) return idResult;
  if (!store.has(idResult)) return err(404, "Item not found");
  store.delete(idResult);
  return ok({ deleted: idResult });
}

const handlers: Record<string, (req: Request) => Response> = {
  GET: handleGet,
  POST: handlePost,
  PUT: handlePut,
  DELETE: handleDelete,
};

export function handleRequest(req: Request): Response {
  const authError = checkAuth(req);
  if (authError) return authError;
  const handler = handlers[req.method];
  if (!handler) return err(405, "Method not allowed");
  return handler(req);
}

import { describe, it, expect } from "vitest";
import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  describe("basic merging", () => {
    it("merges two flat objects", () => {
      const result = deepMerge({ a: 1, b: 2 }, { b: 3, c: 4 } as any);
      expect(result).toEqual({ a: 1, b: 3, c: 4 });
    });

    it("returns a new object (not mutating target)", () => {
      const target = { a: 1 };
      const source = { b: 2 } as any;
      const result = deepMerge(target, source);
      expect(result).not.toBe(target);
      expect(target).toEqual({ a: 1 });
    });

    it("handles empty source", () => {
      const result = deepMerge({ a: 1 }, {});
      expect(result).toEqual({ a: 1 });
    });

    it("handles empty target", () => {
      const result = deepMerge({} as any, { a: 1 } as any);
      expect(result).toEqual({ a: 1 });
    });

    it("handles both empty", () => {
      expect(deepMerge({}, {})).toEqual({});
    });
  });

  describe("nested object merging", () => {
    it("deeply merges nested objects", () => {
      const target = { a: { b: 1, c: 2 } };
      const source = { a: { c: 3, d: 4 } } as any;
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: 1, c: 3, d: 4 } });
    });

    it("merges deeply nested structures", () => {
      const target = { a: { b: { c: { d: 1 } } } };
      const source = { a: { b: { c: { e: 2 } } } } as any;
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: { c: { d: 1, e: 2 } } } });
    });

    it("does not mutate nested target objects", () => {
      const target = { a: { b: 1 } };
      const source = { a: { c: 2 } } as any;
      const result = deepMerge(target, source);
      expect(target.a).toEqual({ b: 1 });
      expect(result.a).not.toBe(target.a);
    });

    it("replaces non-object target with object source", () => {
      const target = { a: 5 as any };
      const source = { a: { b: 1 } } as any;
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: { b: 1 } });
    });

    it("replaces object target with non-object source", () => {
      const target = { a: { b: 1 } as any };
      const source = { a: 5 } as any;
      const result = deepMerge(target, source);
      expect(result).toEqual({ a: 5 });
    });
  });

  describe("array handling", () => {
    it("replaces arrays entirely", () => {
      const result = deepMerge({ a: [1, 2, 3] }, { a: [4, 5] } as any);
      expect(result.a).toEqual([4, 5]);
    });

    it("clones arrays (no shared reference)", () => {
      const source = { a: [1, 2, 3] };
      const result = deepMerge({} as any, source as any);
      expect(result.a).toEqual([1, 2, 3]);
      expect(result.a).not.toBe(source.a);
    });

    it("replaces object with array", () => {
      const result = deepMerge({ a: { b: 1 } as any }, { a: [1, 2] } as any);
      expect(result.a).toEqual([1, 2]);
    });

    it("replaces array with object", () => {
      const result = deepMerge({ a: [1, 2] as any }, { a: { b: 1 } } as any);
      expect(result.a).toEqual({ b: 1 });
    });

    it("handles empty arrays", () => {
      const result = deepMerge({ a: [1, 2] }, { a: [] } as any);
      expect(result.a).toEqual([]);
    });
  });

  describe("Date handling", () => {
    it("clones Date objects", () => {
      const date = new Date("2020-01-01");
      const source = { d: date };
      const result = deepMerge({} as any, source as any);
      expect(result.d).toBeInstanceOf(Date);
      expect((result.d as Date).getTime()).toBe(date.getTime());
      expect(result.d).not.toBe(date);
    });

    it("replaces target Date with source Date", () => {
      const d1 = new Date("2020-01-01");
      const d2 = new Date("2021-01-01");
      const result = deepMerge({ d: d1 }, { d: d2 } as any);
      expect((result.d as Date).getTime()).toBe(d2.getTime());
      expect(result.d).not.toBe(d2);
    });

    it("replaces object with Date", () => {
      const date = new Date();
      const result = deepMerge({ d: { x: 1 } as any }, { d: date } as any);
      expect(result.d).toBeInstanceOf(Date);
    });
  });

  describe("null and undefined", () => {
    it("replaces value with null", () => {
      const result = deepMerge({ a: 1 }, { a: null } as any);
      expect(result.a).toBeNull();
    });

    it("skips undefined values in source", () => {
      const result = deepMerge({ a: 1 }, { a: undefined } as any);
      expect(result.a).toBe(1);
    });

    it("replaces nested object with null", () => {
      const result = deepMerge({ a: { b: 1 } }, { a: null } as any);
      expect(result.a).toBeNull();
    });

    it("preserves target when source key is undefined", () => {
      const result = deepMerge({ a: { b: 1 } }, { a: undefined } as any);
      expect(result.a).toEqual({ b: 1 });
    });
  });

  describe("prototype pollution protection", () => {
    it("ignores __proto__ key", () => {
      const malicious = JSON.parse('{"__proto__": {"polluted": true}}');
      const result = deepMerge({ a: 1 } as any, malicious);
      expect((result as any).polluted).toBeUndefined();
      expect(({} as any).polluted).toBeUndefined();
    });

    it("ignores constructor key", () => {
      const result = deepMerge({ a: 1 } as any, { constructor: { evil: true } } as any);
      expect((result as any).constructor).not.toEqual({ evil: true });
    });

    it("ignores prototype key", () => {
      const result = deepMerge({ a: 1 } as any, { prototype: { evil: true } } as any);
      expect((result as any).prototype).toBeUndefined();
    });

    it("does not pollute Object.prototype", () => {
      deepMerge({} as any, JSON.parse('{"__proto__": {"hacked": 1}}'));
      expect(({} as any).hacked).toBeUndefined();
    });
  });

  describe("symbol keys", () => {
    it("merges symbol keys", () => {
      const sym = Symbol("test");
      const result = deepMerge({ [sym]: 1 } as any, { [sym]: 2 } as any);
      expect((result as any)[sym]).toBe(2);
    });

    it("preserves target symbol keys not in source", () => {
      const sym = Symbol("test");
      const result = deepMerge({ [sym]: 1 } as any, { a: 2 } as any);
      expect((result as any)[sym]).toBe(1);
    });

    it("adds new symbol keys from source", () => {
      const sym = Symbol("new");
      const result = deepMerge({ a: 1 } as any, { [sym]: "val" } as any);
      expect((result as any)[sym]).toBe("val");
    });

    it("merges both string and symbol keys", () => {
      const sym = Symbol("s");
      const result = deepMerge(
        { a: 1, [sym]: { x: 1 } } as any,
        { b: 2, [sym]: { y: 2 } } as any
      );
      expect((result as any).a).toBe(1);
      expect((result as any).b).toBe(2);
      expect((result as any)[sym]).toEqual({ x: 1, y: 2 });
    });
  });

  describe("primitive value handling", () => {
    it("overrides numbers", () => {
      expect(deepMerge({ a: 1 }, { a: 2 } as any)).toEqual({ a: 2 });
    });

    it("overrides strings", () => {
      expect(deepMerge({ a: "x" }, { a: "y" } as any)).toEqual({ a: "y" });
    });

    it("overrides booleans", () => {
      expect(deepMerge({ a: true }, { a: false } as any)).toEqual({ a: false });
    });

    it("handles zero", () => {
      expect(deepMerge({ a: 1 }, { a: 0 } as any)).toEqual({ a: 0 });
    });

    it("handles empty string", () => {
      expect(deepMerge({ a: "x" }, { a: "" } as any)).toEqual({ a: "" });
    });

    it("handles false", () => {
      expect(deepMerge({ a: true }, { a: false } as any)).toEqual({ a: false });
    });
  });

  describe("non-plain objects", () => {
    it("treats class instances as non-plain and replaces", () => {
      class Foo {
        x = 1;
      }
      const foo = new Foo();
      const result = deepMerge({ a: { y: 2 } as any }, { a: foo } as any);
      expect(result.a).toBe(foo);
    });

    it("handles Object.create(null) as plain", () => {
      const obj = Object.create(null);
      obj.b = 2;
      const result = deepMerge({ a: { c: 1 } }, { a: obj } as any);
      expect(result.a).toEqual({ c: 1, b: 2 });
    });
  });

  describe("complex scenarios", () => {
    it("merges a complex mixed structure", () => {
      const target = {
        name: "app",
        config: { debug: false, ports: [8080] },
        created: new Date("2020-01-01"),
        tags: ["a"],
      };
      const source = {
        config: { debug: true, host: "localhost" },
        tags: ["b", "c"],
      } as any;
      const result = deepMerge(target, source);
      expect(result.name).toBe("app");
      expect(result.config).toEqual({ debug: true, ports: [8080], host: "localhost" });
      expect(result.tags).toEqual(["b", "c"]);
      expect(result.created).toBeInstanceOf(Date);
    });

    it("handles multiple levels with all types", () => {
      const target = {
        a: { b: { c: 1, d: [1, 2] }, e: new Date("2020-01-01") },
      };
      const source = {
        a: { b: { c: 99, f: null }, e: new Date("2021-01-01") },
      } as any;
      const result = deepMerge(target, source);
      expect((result.a.b as any).c).toBe(99);
      expect((result.a.b as any).d).toEqual([1, 2]);
      expect((result.a.b as any).f).toBeNull();
    });
  });
});
